		var CFG;
var TIT=null;   
var zoom;
var cut; 
var copy;
var opens=new Array();



function ReplaceResource(recID)
{
	var recValue=Ctrl("main").getResource(recID);
	recValue=Replace(recValue,"#RESOURCE-LIST#"  ,CFG.GetAttr("RESOURCE-LIST"  ));
	recValue=Replace(recValue,"#RESOURCE-ID#"    ,CFG.GetAttr("RESOURCE-ID"    ));
	recValue=Replace(recValue,"#RESOURCE-PARENT#",CFG.GetAttr("RESOURCE-PARENT"));
	recValue=Replace(recValue,"#RESOURCE-OBJECT#",CFG.GetAttr("RESOURCE-OBJECT"));

	Ctrl("main").setResource(recValue, recID);
}

///////////////////////////////////////////////////////////////////////////////          
//EVENTOS
function OnLoad()
{        
	zoom=2;         
	cut=0;

	//Cargo la Configuracion
	CFG   =new NomadXML(Ctrl("main").getResource("QRY_CFG"));

	//Modifico los Recursos
	ReplaceResource("QRY_IDS_PARENT");

	//Actualizo el Titulo
	if ((CFG.GetAttr("RESOURCE-PARENT")!="") && (Ctrl("PARENT").GetXValue()!=""))
	{
		if (TIT==null)
			TIT=GetProxy().SQLService().GetXML(Ctrl("main").getResource("QRY_IDS_PARENT"), '<PARAM IDS="'+Ctrl("PARENT").GetXValue()+'"/>');

		if (TIT!=null) TIT=TIT.FirstChild();
		if (TIT!=null && TIT.GetAttr("descr")!="")
			Ctrl("PAR").SetXValue(" ("+TIT.GetAttr("descr")+")");
	}     

	//Actualizo la Pantalla
	RefreshReport();		
}

function ZoomIn()
{                
	if (zoom>0)
	{ 
		zoom--;        
		RefreshReport();
	}
}

function ZoomOut()
{                
	if (zoom<4)
	{ 
		zoom++;        
		RefreshReport();
	}
}

function RefreshReport()
{
	//Actualizo el URL
	Ctrl("REPORT_ORG").SetURL("../../../ReportViewer.aspx?file=NucleusWF.Base.Definicion.Proceso.rpt&ut="+GetProxy().UserToken()+"&id="+Ctrl("PARENT").GetXValue()+"&mode=DESIGN&now="+datetime2str(new Date()));
	//Ctrl("main").DoEvent("REFRESH_SEARCH");
}                       
var callWindow;
function RolesContexMenu(MyORG,MyID,code,event,wind)
{             
	callWindow=wind;
	Ctrl("ROLE_CM").SetXValue(MyORG+":"+MyID);
	Ctrl("ROLE_CM").EnabledContextMenu("EDIT"  ,(MyID==0                 ?false:true))
	Ctrl("ROLE_CM").EnabledContextMenu("DELETE",(MyID==0 || code=='OWNER'?false:true))
	Ctrl("ROLE_CM").EnabledContextMenu("SI_INI",(MyID==0 || code=='OWNER'?false:true))
	Ctrl("ROLE_CM").EnabledContextMenu("NO_INI",(MyID==0 || code=='OWNER'?false:true))
	Ctrl("ROLE_CM").OnContextMenu(event);
}
function EstadoContexMenu(MyWF,MyID,event,wind)
{                
	callWindow=wind;
	Ctrl("ESTADO_CM").SetXValue(MyWF+":"+MyID);
	Ctrl("ESTADO_CM").EnabledContextMenu("EDIT"  ,(MyID==0?false:true))
	Ctrl("ESTADO_CM").EnabledContextMenu("DELETE",(MyID==0?false:true))
	Ctrl("ESTADO_CM").OnContextMenu(event);
}

function NodeContexMenu(MyParent,MyID,type,event,wind)
{                                         
	callWindow=wind;
	Ctrl("NODE_CM").SetXValue(MyParent+":"+MyID);
	switch(type)
	{
		case "INI":
		case "FIN":
			Ctrl("NODE_CM").EnabledContextMenu("EDIT"  ,true);
			Ctrl("NODE_CM").EnabledContextMenu("DEL"   ,false);
			Ctrl("NODE_CM").EnabledContextMenu("UP"    ,false);
			Ctrl("NODE_CM").EnabledContextMenu("DOWN"  ,false);
			break;
		default:
			Ctrl("NODE_CM").EnabledContextMenu("EDIT"  ,true);
			Ctrl("NODE_CM").EnabledContextMenu("DEL"   ,true);
			Ctrl("NODE_CM").EnabledContextMenu("UP"    ,true);
			Ctrl("NODE_CM").EnabledContextMenu("DOWN"  ,true);
			break;
	}
	Ctrl("NODE_CM").OnContextMenu(event);
}

function NodeNewContexMenu(MyParent,MyOrder,event,wind)
{                
	callWindow=wind;
	Ctrl("NEW_NODE_CM").SetXValue(MyParent+":"+MyOrder);
	Ctrl("NEW_NODE_CM").OnContextMenu(event);
}
function SubProcessContexMenu(MyParent,MyID,event,wind)
{
	callWindow=wind;
	Ctrl("SUBPROCESS_CM").SetXValue(MyParent+":"+MyID);
	Ctrl("SUBPROCESS_CM").OnContextMenu(event);
}
function SubProcessNewContexMenu(MyID,event,wind)
{
	callWindow=wind;
	ParamAdd(MyID);
}



////////////////////////////////////////////////////////////////////////////////////////////////
// ESTADOS
function EstadoAdd(Obj)
{                   
	var MyParent=Obj.GetXValue().split(":")[0];
	var MyID    =Obj.GetXValue().split(":")[1];
	openNewFlowWait("NucleusWF.Base.Definicion.Workflows.ESTADO.MAIN.STD.autoflow","ADD",'<PARAM PARENT="'+MyParent+'"/>',new FlowResult(),"L");
}
function EstadoEdit(Obj)
{
	var MyParent=Obj.GetXValue().split(":")[0];
	var MyID    =Obj.GetXValue().split(":")[1];
	if (MyID=="0") return;
	openNewFlowWait("NucleusWF.Base.Definicion.Workflows.ESTADO.MAIN.STD.autoflow","EDIT",'<PARAM PARENT="'+MyParent+'" ID="'+MyID+'" />',new FlowResult(),"L");
}
function EstadoDelete(Obj)
{
	var MyParent=Obj.GetXValue().split(":")[0];
	var MyID    =Obj.GetXValue().split(":")[1];
	if (MyID=="0") return;
	if (confirm("¿Esta seguro que desea Eliminar el Estado?"))
		openNewFlowWait("NucleusWF.Base.Definicion.Workflows.ESTADO.MAIN.STD.autoflow","DEL",'<PARAM PARENT="'+MyParent+'" ID="'+MyID+'" />',new FlowResult(),"L");
}

