// ACTORES
function ActorAdd(Obj)
{                   
	var MyParent=Obj.GetXValue().split(":")[0];
	var MyID    =Obj.GetXValue().split(":")[1];
	openNewFlowWait("NucleusWF.Base.Definicion.Organigramas.ROLE.MAIN.STD.autoflow","ADD",'<PARAM PARENT="'+MyParent+'"/>',new FlowResult(),"L");
}
function ActorEdit(Obj)
{
	var MyParent=Obj.GetXValue().split(":")[0];
	var MyID    =Obj.GetXValue().split(":")[1];
	if (Obj.GetXValue()=="0") return;
	openNewFlowWait("NucleusWF.Base.Definicion.Organigramas.ROLE.MAIN.STD.autoflow","EDIT",'<PARAM PARENT="'+MyParent+'" ID="'+MyID+'" />',new FlowResult(),"L");
}
function ActorDelete(Obj)
{
	var MyParent=Obj.GetXValue().split(":")[0];
	var MyID    =Obj.GetXValue().split(":")[1];                	

	if (MyID=="0") return; 

  	var rolVal;  
	var nSQL = GetProxy().SQLService();
	rolVal = nSQL.GetXML(Ctrl("main").getResource("QRY_ROL_USOWF"), "<PARAM oi_organigrama=\""+MyParent+"\" oi_role=\""+MyID+"\"/>");

	if(rolVal.GetAttr("flag") != "1")
	{	
	if (confirm("¿Esta seguro que desea Eliminar el Actor?"))
		openNewFlowWait("NucleusWF.Base.Definicion.Organigramas.ROLE.MAIN.STD.autoflow","DEL",'<PARAM PARENT="'+MyParent+'" ID="'+MyID+'" />',new FlowResult(),"L");
	}
	else
	{
		alert("No puede eliminar el Actor, ya que está siendo utilizado dentro de uno o mas nodos de WF que comparten el mismo ORG");
	}	
}
function ActorInicia(Obj)
{
	var MyParent=Obj.GetXValue().split(":")[0];
	var MyID    =Obj.GetXValue().split(":")[1];
	if (MyID=="0") return;
	openNewFlowWait("NucleusWF.Base.Definicion.Workflows.PROCESS.flow","ROLE_INICIA",'<PARAMS PARENT="'+Ctrl("PARENT").GetXValue()+'"  ID="'+MyID+'" />',new FlowResult(),"L");
}
function ActorNoInicia(Obj)
{
	var MyParent=Obj.GetXValue().split(":")[0];
	var MyID    =Obj.GetXValue().split(":")[1];
