	openNewFlowWait("NucleusWF.Base.Definicion.Workflows.PROCESS.flow","ROLE_NO_INICIA",'<PARAMS PARENT="'+Ctrl("PARENT").GetXValue()+'"  ID="'+MyID+'" />',new FlowResult(),"L");
