////////////////////////////////////////////////////////////////////////////////////////////////
function FlowResult()
{
	this.processResult = function(xml)
	{                      
		var RS=GetProxy().SQLService().GetXML(Ctrl("main").getResource("QRY_REFRESH"), '<PARAMS id="'+Ctrl("PARENT").GetXValue()+'" />');
		callWindow.Refresh(RS);
	}
}


function RESULT()
{
	cut=0;           
	var MyParent=Ctrl("PARENT").GetXValue();
	var MyId    =Ctrl("hid_val").GetXValue();
	var MyWF    =Ctrl("WF").GetXValue();
	openNewFlowWait("NucleusWF.Base.Definicion.Workflows.NODE.flow","NODE_EDIT",'<PARAMS oi_workflow="'+MyWF+'" PARENT="'+MyParent+'"  ID="'+MyId+'" />',new FlowEditNode(),"L");
}

function FlowEditNode()
{
	this.processResult = function(xml)
	{
		refresh_search();		
	}	
} 
function refresh_search()
{
	if(Ctrl("UrlControl02").GetXValue() != "")
		Ctrl("main").DoEvent("REFRESH_SEARCH");
}

function SubProcessExpand(e_subproceso)
{                              
	opens.push(e_subproceso.toString());
	RefreshReport();
}

